/**
 * Menu Module Public API
 *
 * Centralized exports for the Menu module.
 * Import from this file when using menu module functionality
 * from other parts of the application.
 *
 * @module modules/menu
 *
 * @example
 * ```typescript
 * import {
 *   MenuModule,
 *   MenuService,
 *   menuRoutes,
 *   type Menu,
 *   type CreateMenuRequest,
 * } from '@/modules/menu';
 * ```
 */

// -----------------------------------------------------------------------------
// Module Definition
// -----------------------------------------------------------------------------

export { MenuModule, default } from '@/modules/menu/menu.module';
export type {
  MenuModuleContext,
  MenuModuleHooks,
} from '@/modules/menu/menu.module';

// -----------------------------------------------------------------------------
// Services
// -----------------------------------------------------------------------------

export { MenuService } from '@/modules/menu/menu.service';
export type {
  CreateMenuResponse,
  UpdateMenuResponse,
  PublishMenuResponse,
  UnpublishMenuResponse,
  UpdateSettingsResponse,
  DuplicateMenuResponse,
} from '@/modules/menu/menu.service';

export { CategoryService } from '@/modules/menu/category.service';
export type {
  CreateCategoryResponse,
  UpdateCategoryResponse,
  ReorderCategoriesResponse,
} from '@/modules/menu/category.service';

export { ProductService } from '@/modules/menu/product.service';
export type {
  CreateProductResponse,
  UpdateProductResponse,
  CreateVariantResponse,
  UpdateVariantResponse,
  CreateModifierResponse,
  UpdateModifierResponse,
  UpdateNutritionInfoResponse,
  UpdateAvailabilityResponse,
  ReorderProductsResponse,
} from '@/modules/menu/product.service';

// -----------------------------------------------------------------------------
// Repositories
// -----------------------------------------------------------------------------

export { MenuRepository } from '@/modules/menu/menu.repository';
export type {
  PaginatedResult,
  MenuSummary,
  CreateMenuData,
  UpdateMenuData,
} from '@/modules/menu/menu.repository';

export { CategoryRepository } from '@/modules/menu/category.repository';

export { ProductRepository } from '@/modules/menu/product.repository';

// -----------------------------------------------------------------------------
// Controllers
// -----------------------------------------------------------------------------

export {
  MenuController,
  CategoryController,
  ProductController,
} from '@/modules/menu/menu.controller';

// -----------------------------------------------------------------------------
// Routes
// -----------------------------------------------------------------------------

export {
  menuRoutes,
  categoryRoutes,
  productRoutes,
  menuModuleRoutes,
  buildMenuApiPath,
  buildMenuAdminPath,
  buildCategoryApiPath,
  buildProductApiPath,
  isPublicMenuRoute,
  isProtectedMenuRoute,
  menuEndpoints,
  categoryEndpoints,
  productEndpoints,
} from '@/modules/menu/menu.routes';
export type {
  MenuRouteConfig,
  CategoryRouteConfig,
  ProductRouteConfig,
  MenuModuleRouteConfig,
  MenuEndpointMetadata,
} from '@/modules/menu/menu.routes';

// -----------------------------------------------------------------------------
// Events
// -----------------------------------------------------------------------------

export {
  MENU_MODULE_EVENTS,
  emitMenuCreated,
  emitMenuUpdated,
  emitMenuDeleted,
  emitMenuPublished,
  emitCategoryCreated,
  emitCategoryReordered,
  emitProductCreated,
  emitProductAvailabilityChanged,
} from '@/modules/menu/menu.events';
export type {
  MenuModuleEvents,
  MenuModuleEventName,
  BaseEventPayload,
  MenuCreatedEventPayload,
  MenuUpdatedEventPayload,
  MenuDeletedEventPayload,
  MenuRestoredEventPayload,
  MenuPublishedEventPayload,
  MenuUnpublishedEventPayload,
  MenuSettingsUpdatedEventPayload,
  CategoryCreatedEventPayload,
  CategoryUpdatedEventPayload,
  CategoryDeletedEventPayload,
  CategoryReorderedEventPayload,
  ProductCreatedEventPayload,
  ProductUpdatedEventPayload,
  ProductDeletedEventPayload,
  ProductAvailabilityChangedEventPayload,
  ProductsReorderedEventPayload,
  VariantCreatedEventPayload,
  VariantUpdatedEventPayload,
  VariantDeletedEventPayload,
  ModifierCreatedEventPayload,
  ModifierUpdatedEventPayload,
  ModifierDeletedEventPayload,
  ThemeCreatedEventPayload,
  ThemeUpdatedEventPayload,
  ThemeDeletedEventPayload,
} from '@/modules/menu/menu.events';

// -----------------------------------------------------------------------------
// Types - Core Entities
// -----------------------------------------------------------------------------

export type {
  // Menu types
  Menu,
  MenuWithRelations,
  MenuSettings,
  CreateMenuRequest,
  UpdateMenuRequest,
  PublishMenuRequest,
  ListMenusQuery,
  MenuResponse,

  // Category types
  Category,
  CategoryWithRelations,
  CreateCategoryRequest,
  UpdateCategoryRequest,
  ReorderCategoriesRequest,
  ListCategoriesQuery,
  CategoryTreeNode,

  // Product types
  Product,
  ProductWithRelations,
  CreateProductRequest,
  UpdateProductRequest,
  UpdateAvailabilityRequest,
  ListProductsQuery,

  // Variant types
  ProductVariant,
  CreateVariantRequest,
  UpdateVariantRequest,

  // Modifier types
  ProductModifier,
  CreateModifierRequest,
  UpdateModifierRequest,

  // Allergen types
  Allergen,
  AllergenWithPivot,

  // Nutrition types
  NutritionInfo,
  CreateNutritionInfoRequest,
  UpdateNutritionInfoRequest,

  // Theme types
  Theme,
  ThemeSettings,
  CreateThemeRequest,
  UpdateThemeRequest,
  ListThemesQuery,

  // QR Code reference type
  QRCodeRef,

  // Public menu types
  PublicMenuResponse,

  // Module settings
  MenuModuleSettings,
} from '@/modules/menu/menu.types';

// -----------------------------------------------------------------------------
// Types - Event Payloads (from types file)
// -----------------------------------------------------------------------------

export type {
  MenuCreatedEvent,
  MenuUpdatedEvent,
  MenuDeletedEvent,
  MenuPublishedEvent,
  ProductCreatedEvent,
  ProductAvailabilityChangedEvent,
  CategoryReorderedEvent,
} from '@/modules/menu/menu.types';

// -----------------------------------------------------------------------------
// Types - Hook Contexts (from types file)
// -----------------------------------------------------------------------------

export type {
  BeforeMenuCreateContext,
  AfterMenuCreateContext,
  BeforeMenuPublishContext,
  AfterMenuPublishContext,
  BeforeProductCreateContext,
  AfterProductCreateContext,
} from '@/modules/menu/menu.types';

// -----------------------------------------------------------------------------
// Schemas (Zod validation)
// -----------------------------------------------------------------------------

export {
  // Menu schemas
  createMenuSchema,
  updateMenuSchema,
  publishMenuSchema,
  listMenusQuerySchema,
  menuSettingsSchema,
  generateSlug,

  // Category schemas
  createCategorySchema,
  updateCategorySchema,
  reorderCategoriesSchema,
  listCategoriesQuerySchema,

  // Product schemas
  createProductSchema,
  updateProductSchema,
  updateAvailabilitySchema,
  listProductsQuerySchema,

  // Variant schemas
  createVariantSchema,
  updateVariantSchema,

  // Modifier schemas
  createModifierSchema,
  updateModifierSchema,

  // Nutrition schemas
  createNutritionInfoSchema,
  updateNutritionInfoSchema,

  // Theme schemas
  createThemeSchema,
  updateThemeSchema,
  listThemesQuerySchema,
  themeSettingsSchema,
} from '@/modules/menu/menu.schema';

export type {
  CreateMenuInput,
  UpdateMenuInput,
  PublishMenuInput,
  ListMenusQueryInput,
  CreateCategoryInput,
  UpdateCategoryInput,
  ReorderCategoriesInput,
  ListCategoriesQueryInput,
  CreateProductInput,
  UpdateProductInput,
  UpdateAvailabilityInput,
  ListProductsQueryInput,
  CreateVariantInput,
  UpdateVariantInput,
  CreateModifierInput,
  UpdateModifierInput,
  CreateNutritionInfoInput,
  UpdateNutritionInfoInput,
  CreateThemeInput,
  UpdateThemeInput,
  ListThemesQueryInput,
} from '@/modules/menu/menu.schema';
